import{_ as p,o as e,c as a,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const D=JSON.parse('{"title":"驱魔人","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/通用及综合类/驱魔人/驱魔人.md","filePath":"4.资源分区/6.技艺及称号/通用及综合类/驱魔人/驱魔人.md"}'),s={name:"4.资源分区/6.技艺及称号/通用及综合类/驱魔人/驱魔人.md"};function o(d,b,l,_,i,c){return e(),a("div",null,[...b[0]||(b[0]=[r("h1",{id:"驱魔人",tabindex:"-1"},[t("驱魔人 "),r("a",{class:"header-anchor",href:"#驱魔人","aria-label":'Permalink to "驱魔人"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"灵魂蓝调013")])])],-1),n('<h1 id="驱魔人-1" tabindex="-1">驱魔人 <a class="header-anchor" href="#驱魔人-1" aria-label="Permalink to &quot;驱魔人&quot;">​</a></h1><p>驱魔人</p><p>本质：魔幻本质<br> 描述：我神的荣光需要彰显！<br> 特殊：该资源下所有提及到的神术检定，均为为【决心+学识（神学）+辅助专业：虔诚（专注）】</p><p>因信称义：现在在初次面见你之后，黑暗生物、邪恶阵营（不包括PL）的目标初始好感对你下降一级，至多降至敌对，由ST裁定是否有特殊情况。</p><p>西方虔诚：你不能修习黑暗或邪恶的招式、能量（比如妖力和黑暗原力），也不能习得与使用法术，若原本拥有则立即失去。<br> 这是一个泛基督教信仰导向能力。</p><p>教会的正职<br> 价格：D+500<br> 圣言圣事：你获得一本圣经，其数据如下：<br> 圣经<br> 本质：魔幻本质<br> 分类：道具（书）<br> 体积：1<br> 描述：《圣经》又名《新旧约全书》，由《旧约》《新约》组成。《旧约》一共有三十九卷，《新约》一共27卷。神与他的使徒——人类的圣言圣事被在其上一一记述，它代表人与上帝的圣约，保护世人不受魔鬼的侵犯。<br> 圣约：当你进行神术检定时，你每有2点传奇决心，则获得1点神圣加值。当你持有圣经进行攻击时，该攻击效果自动视为拥有【银】特性，并且对于拥有畏惧阳光相关特性的目标而言，该次攻击与阳光等同。</p><p>神术：仅对于黑暗生物、灵体、虚体、不死生物或者任何被视为恶魔与魔鬼的目标，你可以消费标准动作对射程15米内的一个目标以神术检定进行攻击，造成严重正能量伤害，具有【法破】。<br> 特殊的是，对于附身于他人身上，或者寄生在他人体内的此类目标，你可以指定其附身或寄生的目标。</p><p>驱魔人专长<br> 圣战（1）<br> 1级：你的神术攻击可以选择对任何目标进行攻击，而不止局限于黑暗生物、灵体、虚体、不死生物或者任何被视为恶魔与魔鬼的目标，同时在攻击中获得1点表现加值。</p><p>解放神学（1）<br> 1级：神学不仅要反思世界，而且要改造世界；正是通过耶稣，才了解真正的解放是什么，该如何得到真正的解放。<br> 你的信仰导向替换为【解放神学】，在防御上获得1点表现加值。</p><p>公职（2）<br> 2级：在进入轮回时你将自动获得如同当地普通市民一般的身份证明材料（例如身份证），如果当前世界存在类似基督教之类的概念，你会获得作为牧师的相关证件。但这些身份作为异地办理在当地档案记录中不会有任何过往经历，所以也有被追查出漏洞的可能，这是一个D级命运来源的背景身份。<br> 当你宣言自己是牧师时，对方会因为你身上的氛围而而忽视你奇怪的外貌之类让人意外但并非不能接受的异常而信任你的牧师身份。但这不意味着如果你做出可疑的事情不会被怀疑。此外不同人对于牧师的态度也不相同，这与你的声望以及当前世界相关，具体还是由ST决定。</p><p>驱魔人物品<br> 十字圣装<br> 价格：D+500<br> 你获得一把圣本笃十字架，你可以把它安放在圣经之中。<br> 圣本笃十字架：武器伤害6L，该武器可以进行神术攻击时使用，将武器伤害计入神术攻击检定中，该武器的材质为木。<br> 只要持有圣本笃十字架，你就视为同时具有黑暗视觉与灵感视觉。</p><p>升级-神圣庇护（C+1000）：消费移动动作执行祷告，在接下来的一个场景中，你以学识+专业：神学代替正常武技执行格挡，在格挡中还会获得6DP的表现防御加值。<br> 这个升级等同于购买了一个技艺而不是物品。</p><p>公职牧师袍<br> 本质：魔幻本质<br> 价格：D+500<br> 分类：轻甲<br> 描述：泛基督教牧师的牧师袍，代表着一种身份，为朴素的纯白色，没有太多装饰，胸口有着银白色十字架标志，散发着香料的气味。<br> 盔甲基本属性：盔甲防御4/4<br> 盔甲特殊属性：【全伤害吸收1】<br> 洁净：这件牧师袍具备自动清洁功能，因此永远不会沾染上一丝一毫的污迹。<br> 低语：本盔甲提供的不是防御加值，而是偏斜防御，同时你每有1点传奇决心，该盔甲提供的偏斜防御就提升1点。</p><p>驱魔人技能<br> 祝圣<br> 价格：D+500<br> 描述：为你的武器祝圣，为你的盔甲祝圣，为你的枪械祝圣，并不包括神圣手榴弹这种产物。<br> 效果：消费一个花招动作，你为接触到的一件盔甲或武器祝圣。<br> 如果是武器，那么武器攻击获得5DP加值。<br> 如果是盔甲，那么盔甲防御增加5DP加值。<br> 你必须在购买时选择该技能是为武器还是盔甲祝圣，购买后可以再购买一次没购买的效果。<br> 被祝圣的武器或盔甲同时只能存在一件，祝圣的效果将会持续一日。<br> 特殊：通过此方式祝圣物品将无视类似诅咒机魂的影响，物品功能失效等效果，于画面效果上视为天使然德基尔手下的灵以主的名义前来，令机魂从属于与主同在的牧者。</p><p>虔诚祷念<br> 价格：D+500<br> 动作：被动<br> 描述：每日的必修课就是向主祈祷，在祈祷中聆听主的启示。<br> 效果：你获得C级免疫措手不及的效果，同时提升4点先攻。</p><p>蔷薇反击<br> 价格：C+1000<br> 动作：被动<br> 描述：在谈到杀人之律例时，上帝说道：“人若彼此争斗，伤害有孕的妇人，甚至堕胎， 随后却无别的害人之处，那伤害他的总要按妇人的丈夫所要求的，照审判官所断的受罚。若有别害，就要以命偿命，以眼还眼，以牙还牙，以手还手，以脚还脚，以烙还烙，以伤还伤，以打还打。”<br> 效果：你获得基于偏斜防御的反伤效果，受到伤害时对攻击者造成3点严重伤害，伤害性质为正能量。</p><p>硫磺与火<br> 前提：圣战<br> 价格：C+1000<br> 动作：迅捷<br> 持续：一轮<br> 描述：当时，耶和华将硫磺与火从天上耶和华那里降与所多玛和蛾摩拉，把那些城和全平原，并城里所有的居民，连地上生长的，都毁灭了。<br> 效果：你可以选择将下次神术攻击造成的伤害类型改变为火焰伤害，这次伤害需以强韧检定进行豁免，此外射程距离提高至20米或造成一半距离扇形的范围伤害。</p><p>防御圣言<br> 前提：祝圣（盔甲）<br> 价格：C+1000<br> 描述：我要论到耶和华说，他是我的避难所，是我的山寨，是我的神，是我所依靠的。我不必害怕黑夜的惊骇，抑或是黑暗中的恶魔，因为耶和华是我的避难所。<br> 效果：你的祝圣（盔甲）效果可以对于身边5米范围内的所有友方单位（包括自己）生效，同时防御提升的效果提升至10DP。</p><p>升级（C+1000）：祝圣带来的防御再提升5点，你将在一场景内获得B级胁迫，支配，思维控制来源的免疫，同时对祝圣效果范围内的其他友方单位生效。</p><p>狱火断罪之剑<br> 价格：B+2000<br> 描述：此剑乃是正义天使乌列尔手中的圣剑，是裁断罪恶、镇守地狱之门的神剑，当然你手里的只是它的一个化形，因信仰与虔诚召唤来。<br> 效果：你必须在持有圣本笃十字架的情况下使用该技艺，以断罪之剑重组十字架，这需要一个移动动作，效果持续一场景。<br> 重组后，该武器伤害将上升15点，被该武器击杀的单位视为承受A级禁止复活能力效果。当使用该武器时，每轮一次，你可以以自由动作进行一次格挡行为。</p><p>与神同在<br> 价格：B+2000<br> 动作：被动<br> 描述：我专心爱他，他就搭救我，我若求告他，他就应允我，我在急难中，他会与我同在，他会搭救我，使我尊贵。<br> 效果：一影片一次，只在受到致死伤害时生效，你免疫那次伤害。这是一个B级命运来源的无敌效果。</p><p>宣魔圣战<br> 价格：A+4000<br> 描述：在上帝的眼里，一个有道德的穷苦农民和老妇人，比一个富有而有罪的主教高得多！<br> 效果：当你面对一个事实上广泛进行罪恶行径的宗教团体时（包括但不限于征收恕罪券的罗马教廷、举行人祭的邪教等等，由ST/团审定义），你可以以标准动作宣告其有违神意并且进行一次神术攻击检定，该宗教团体中所有学识不低于3级的目标立即查觉并且均可以以相同的神攻击检定进行对抗。<br> 若无人比你的出目更高，则该宗教团体所有人永久失去来自其信仰导向及神灵带来的一切好处。<br> 由于该效果过于模糊，ST与PL有权将效果改为：以一个标准动作，针对事实上广泛进行罪恶行径的单位，你对其的攻击射程上升到敏感范围，且可以对射程范围的所有敌方单位进行攻击。被造成伤害的单位需进行一次神术检定/意志豁免对抗，DC为伤害值，失败则受到A级命运来源的即死效果。</p><p>选开：<br> 紫衣在世<br> 价格：S+8000<br> 描述：你与神同行。<br> 效果：轮回开始时，你的身份锁定为【教皇】，这是一个S级命运来源的背景身份。<br> 当你死亡时，你将会在三日后复活，这是一个S级命运来源的复活效果。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',25)])])}const f=p(s,[["render",o]]);export{D as __pageData,f as default};
